  // T45: de-heartbeated footer + PRESENT/LOCKED tooltips, and the lock-screen relay-picker strings.
  const T45 = {
    en:{"footer":"NADO light-miner · the chain stays on full nodes; this page only generates keys, registers, and renews your presence lease. Your reward lands on your address because a relay builds the block crediting it.","tip.present":"PRESENT — you hold a valid presence lease (a recent PoSW recert), so you're currently ELIGIBLE to win open-lane blocks. The wallet renews the lease automatically before it lapses; if it stops, presence lapses and you stop earning until it resumes.","tip.locked":"MINING WHILE LOCKED — your PoSW presence lease stays valid on-chain, so a locked/asleep phone keeps mining until it lapses. Renewing the lease (a fresh post-quantum PoSW recert) needs your phone active, so reopen the app before this runs out — it renews in about a second, automatically. (Sending a transaction always needs your phone unlocked at that moment.)","unlock.relayToggle":"Change relay node","unlock.relayNote":"If your relay is unreachable you could get locked out. Set a working full-node URL here so the app can connect."},
    cs:{"footer":"NADO light-miner · řetězec zůstává na plných uzlech; tato stránka jen generuje klíče, registruje a obnovuje váš lease přítomnosti. Vaše odměna přistane na vaší adrese, protože relay sestaví blok, který ji připíše.","tip.present":"PŘÍTOMEN — držíte platný lease přítomnosti (nedávná PoSW recertifikace), takže právě teď máte NÁROK vyhrávat bloky ve volné dráze. Peněženka lease automaticky obnovuje dřív, než vyprší; pokud se to zastaví, přítomnost vyprší a přestanete vydělávat, dokud se obnovování znovu nerozběhne.","tip.locked":"TĚŽBA PŘI ZAMČENÍ — váš PoSW lease přítomnosti zůstává v řetězci platný, takže zamčený nebo uspaný telefon těží dál, dokud nevyprší. Obnovení lease (nová postkvantová PoSW recertifikace) vyžaduje aktivní telefon, takže aplikaci znovu otevřete dřív, než tohle vyprší — obnoví se automaticky, zhruba za sekundu. (Odeslání transakce vždy vyžaduje telefon odemčený právě v tu chvíli.)","unlock.relayToggle":"Změnit relay uzel","unlock.relayNote":"Pokud je váš relay nedostupný, můžete ztratit přístup. Zadejte sem funkční URL plného uzlu, aby se aplikace mohla připojit."},
    es:{"footer":"Minero ligero de NADO · la cadena vive en los nodos completos; esta página solo genera claves, te registra y renueva tu concesión de presencia. Tu recompensa llega a tu dirección porque un relay construye el bloque que la acredita.","tip.present":"PRESENTE — tienes una concesión de presencia válida (una recertificación PoSW reciente), así que ahora mismo eres ELEGIBLE para ganar bloques del carril abierto. La cartera renueva la concesión automáticamente antes de que caduque; si se detiene, la presencia caduca y dejas de ganar hasta que se reanude.","tip.locked":"MINANDO CON EL TELÉFONO BLOQUEADO — tu concesión de presencia PoSW sigue siendo válida en la cadena, así que un teléfono bloqueado o en reposo sigue minando hasta que caduque. Renovar la concesión (una nueva recertificación PoSW poscuántica) requiere el teléfono activo, así que vuelve a abrir la app antes de que esto se agote — se renueva en aproximadamente un segundo, de forma automática. (Enviar una transacción siempre requiere el teléfono desbloqueado en ese momento.)","unlock.relayToggle":"Cambiar nodo de relay","unlock.relayNote":"Si tu relay no está accesible, podrías quedar bloqueado. Configura aquí la URL de un nodo completo que funcione para que la app pueda conectarse."},
    pt:{"footer":"NADO light-miner · a cadeia mantém-se nos nós completos; esta página apenas gera chaves, faz o registo e renova a tua concessão de presença. A tua recompensa chega ao teu endereço porque um relay constrói o bloco que o credita.","tip.present":"PRESENTE — tens uma concessão de presença válida (uma recertificação PoSW recente), por isso estás atualmente ELEGÍVEL para ganhar blocos da via aberta. A carteira renova a concessão automaticamente antes de caducar; se parar, a presença caduca e deixas de ganhar até retomar.","tip.locked":"A MINERAR ENQUANTO BLOQUEADO — a tua concessão de presença PoSW mantém-se válida na cadeia, por isso um telemóvel bloqueado/em suspensão continua a minerar até caducar. Renovar a concessão (uma nova recertificação PoSW pós-quântica) exige o telemóvel ativo, por isso reabre a app antes de isto esgotar — renova-se em cerca de um segundo, automaticamente. (Enviar uma transação exige sempre o telemóvel desbloqueado nesse momento.)","unlock.relayToggle":"Alterar nó de relay","unlock.relayNote":"Se o teu relay estiver inacessível, podes ficar sem acesso. Define aqui um URL de nó completo funcional para a app se poder ligar."},
    fr:{"footer":"Mineur léger NADO · la chaîne réside sur les nœuds complets ; cette page ne fait que générer des clés, vous enregistrer et renouveler votre bail de présence. Votre récompense arrive sur votre adresse parce qu'un relais construit le bloc qui la crédite.","tip.present":"PRÉSENT — vous détenez un bail de présence valide (une récertification PoSW récente), vous êtes donc actuellement ÉLIGIBLE pour gagner des blocs de la voie ouverte. Le portefeuille renouvelle le bail automatiquement avant qu'il n'expire ; s'il s'interrompt, la présence expire et vous cessez de gagner jusqu'à ce qu'elle reprenne.","tip.locked":"MINAGE VERROUILLÉ — votre bail de présence PoSW reste valide sur la chaîne : un téléphone verrouillé ou en veille continue donc de miner jusqu'à l'expiration du bail. Renouveler le bail (une nouvelle récertification PoSW post-quantique) exige un téléphone actif ; rouvrez donc l'application avant l'expiration — le renouvellement prend environ une seconde, automatiquement. (Envoyer une transaction nécessite toujours que votre téléphone soit déverrouillé à ce moment-là.)","unlock.relayToggle":"Changer de nœud relais","unlock.relayNote":"Si votre relais est injoignable, vous risquez d'être bloqué. Indiquez ici l'URL d'un nœud complet fonctionnel pour que l'application puisse se connecter."},
    de:{"footer":"NADO Light-Miner · Die Chain liegt auf den Full Nodes; diese Seite erzeugt nur Schlüssel, registriert und erneuert deine Präsenz-Lease. Deine Belohnung landet auf deiner Adresse, weil ein Relay den Block erstellt, der sie ihr gutschreibt.","tip.present":"ANWESEND — du hältst eine gültige Präsenz-Lease (eine aktuelle PoSW-Rezertifizierung), du bist also derzeit BERECHTIGT, Open-Lane-Blöcke zu gewinnen. Die Wallet erneuert die Lease automatisch, bevor sie abläuft; wenn das aussetzt, läuft die Präsenz aus und du verdienst nichts mehr, bis es wieder anläuft.","tip.locked":"MINEN IM GESPERRTEN ZUSTAND — deine PoSW-Präsenz-Lease bleibt on-chain gültig, ein gesperrtes/schlafendes Handy mint also weiter, bis sie abläuft. Das Erneuern der Lease (eine frische post-quantum PoSW-Rezertifizierung) erfordert ein aktives Handy, öffne die App also wieder, bevor sie abläuft — sie erneuert sich automatisch in etwa einer Sekunde. (Zum Senden einer Transaktion muss dein Handy in diesem Moment immer entsperrt sein.)","unlock.relayToggle":"Relay-Node wechseln","unlock.relayNote":"Wenn dein Relay nicht erreichbar ist, könntest du ausgesperrt werden. Trage hier die URL eines funktionierenden Full Nodes ein, damit die App sich verbinden kann."},
    it:{"footer":"NADO light-miner · la catena resta sui full node; questa pagina si limita a generare le chiavi, registrarti e rinnovare la tua lease di presenza. La tua ricompensa arriva sul tuo indirizzo perché è un relay a costruire il blocco che te la accredita.","tip.present":"PRESENTE — possiedi una lease di presenza valida (una recente ricertificazione PoSW), quindi al momento sei IDONEO a vincere blocchi della corsia aperta. Il wallet rinnova la lease automaticamente prima che scada; se si interrompe, la presenza decade e smetti di guadagnare finché non riprende.","tip.locked":"MINARE A TELEFONO BLOCCATO — la tua lease di presenza PoSW resta valida on-chain, quindi un telefono bloccato o in sospensione continua a minare finché non scade. Il rinnovo della lease (una nuova ricertificazione PoSW post-quantum) richiede il telefono attivo, quindi riapri l'app prima che questa scada — il rinnovo dura circa un secondo, in automatico. (L'invio di una transazione richiede sempre il telefono sbloccato in quel momento.)","unlock.relayToggle":"Cambia nodo relay","unlock.relayNote":"Se il tuo relay è irraggiungibile potresti restare tagliato fuori. Imposta qui l'URL di un full node funzionante così l'app può connettersi."},
    ru:{"footer":"Лёгкий майнер NADO · сама цепь держится на полных узлах; эта страница лишь генерирует ключи, регистрирует вас и продлевает вашу аренду присутствия. Награда попадает на ваш адрес, потому что реле формирует блок, который её начисляет.","tip.present":"ПРИСУТСТВУЮ — у вас есть действующая аренда присутствия (свежая переаттестация PoSW), поэтому прямо сейчас вы ИМЕЕТЕ ПРАВО выигрывать блоки открытой полосы. Кошелёк продлевает аренду автоматически, прежде чем она истечёт; если он остановится, присутствие прекращается, и вы перестаёте зарабатывать, пока оно не возобновится.","tip.locked":"МАЙНИНГ ПРИ БЛОКИРОВКЕ — ваша аренда присутствия PoSW остаётся действительной в цепи, поэтому заблокированный или спящий телефон продолжает майнить, пока она не истечёт. Для продления аренды (свежая постквантовая переаттестация PoSW) телефон должен быть активен, поэтому откройте приложение снова, прежде чем срок закончится — продление занимает около секунды и происходит автоматически. (Для отправки транзакции телефон в этот момент всегда должен быть разблокирован.)","unlock.relayToggle":"Сменить релейный узел","unlock.relayNote":"Если ваше реле недоступно, вы можете потерять доступ. Укажите здесь рабочий URL полного узла, чтобы приложение могло подключиться."},
    zh:{"footer":"NADO 轻量矿机 · 完整链数据保存在全节点上；本页面只负责生成密钥、完成注册并续期你的在场租约。你的奖励之所以能记入你的地址，是因为有中继节点构建了为该地址记账的区块。","tip.present":"PRESENT — 你持有一份有效的在场租约（近期的 PoSW 重新认证），因此当前有资格赢得开放通道区块。钱包会在租约失效前自动续期；一旦停止续期，在场状态就会失效，你将停止获得奖励，直到续期恢复。","tip.locked":"MINING WHILE LOCKED — 你的 PoSW 在场租约在链上依然有效，因此手机锁屏或休眠时仍会持续挖矿，直到租约失效。续期租约（一次全新的抗量子 PoSW 重新认证）需要手机处于活动状态，所以请在到期前重新打开应用——续期会自动完成，大约只需一秒。（发送交易时，仍必须在那一刻解锁手机。）","unlock.relayToggle":"更换中继节点","unlock.relayNote":"如果你的中继节点无法连接，你可能会被拒之门外。请在此填写一个可用的全节点 URL，以便应用能够连接。"},
    ja:{"footer":"NADO ライトマイナー · チェーンはフルノードが保持します。このページは鍵の生成、登録、そしてプレゼンス・リース(presence lease)の更新のみを行います。報酬があなたのアドレスに入るのは、それを計上したブロックをリレーが構築するためです。","tip.present":"PRESENT — 有効なプレゼンス・リース(直近の PoSW 再認証)を保持しているため、現在オープンレーンのブロックを獲得する資格があります。ウォレットはリースが失効する前に自動で更新します。更新が止まるとプレゼンスが失効し、再開するまで報酬を得られなくなります。","tip.locked":"MINING WHILE LOCKED — PoSW プレゼンス・リースはオンチェーン上で有効なまま保たれるため、ロック中やスリープ中の端末でも失効するまでマイニングを続けます。リースの更新(新しい耐量子 PoSW 再認証)には端末がアクティブである必要があるので、期限が切れる前にアプリを開き直してください。更新は約1秒で自動的に完了します。(トランザクションの送信には、その時点で端末のロックを解除しておく必要があります。)","unlock.relayToggle":"リレーノードを変更","unlock.relayNote":"リレーに接続できないと、締め出されてしまう可能性があります。アプリが接続できるよう、稼働中のフルノードの URL をここに設定してください。"},
    ko:{"footer":"NADO 라이트 마이너 · 체인은 풀 노드에서 유지됩니다. 이 페이지는 키를 생성하고, 등록하고, 여러분의 프레즌스 리스(presence lease, 존재 임대)를 갱신하는 역할만 합니다. 릴레이가 여러분의 주소로 보상을 지급하는 블록을 만들어 주기 때문에 보상이 여러분의 주소로 들어옵니다.","tip.present":"PRESENT — 유효한 프레즌스 리스(최근 PoSW 재인증)를 보유하고 있으므로, 현재 오픈 레인 블록을 획득할 자격이 있는(ELIGIBLE) 상태입니다. 지갑이 리스가 만료되기 전에 자동으로 갱신합니다. 갱신이 멈추면 프레즌스가 만료되어, 다시 시작될 때까지 채굴 보상을 받지 못합니다.","tip.locked":"MINING WHILE LOCKED — PoSW 프레즌스 리스가 온체인에서 유효하게 유지되므로, 잠기거나 절전 상태인 휴대폰도 리스가 만료될 때까지 계속 채굴합니다. 리스 갱신(새로운 양자 내성 PoSW 재인증)에는 휴대폰이 활성 상태여야 하므로, 리스가 만료되기 전에 앱을 다시 열어 주세요 — 갱신은 약 1초 만에 자동으로 이루어집니다. (트랜잭션을 전송할 때는 항상 그 순간에 휴대폰 잠금이 해제되어 있어야 합니다.)","unlock.relayToggle":"릴레이 노드 변경","unlock.relayNote":"릴레이에 연결할 수 없으면 접속이 차단될 수 있습니다. 앱이 연결할 수 있도록 작동 중인 풀 노드 URL을 여기에 설정하세요."},
    ar:{"footer":"مُعدِّن NADO الخفيف · تبقى السلسلة على العُقد الكاملة؛ وتقتصر هذه الصفحة على إنشاء المفاتيح والتسجيل وتجديد عقد حضورك. تصل مكافأتك إلى عنوانك لأنّ عُقدة مُرحِّلة (relay) تبني الكتلة التي تُقيَّد فيها المكافأة لعنوانك.","tip.present":"PRESENT — لديك عقد حضور صالح (إعادة توثيق PoSW حديثة)، لذا فأنت الآن مؤهَّل للفوز بكتل المسار المفتوح. تُجدِّد المحفظة العقد تلقائيًا قبل انقضائه؛ وإن توقّف ذلك، انقضى الحضور وتوقّف كسبك حتى يُستأنف.","tip.locked":"MINING WHILE LOCKED — يظل عقد حضور PoSW الخاص بك صالحًا على السلسلة، لذا يواصل الهاتف المقفل أو النائم التعدين حتى ينقضي العقد. أمّا تجديد العقد (إعادة توثيق PoSW جديدة مقاومة للكمّ) فيتطلّب أن يكون هاتفك نشطًا، لذا أعِد فتح التطبيق قبل انتهاء المدة — إذ يتجدّد تلقائيًا خلال ثانية تقريبًا. (وإرسال أي معاملة يتطلّب دائمًا أن يكون هاتفك غير مقفل في تلك اللحظة.)","unlock.relayToggle":"تغيير عُقدة الترحيل","unlock.relayNote":"إذا تعذّر الوصول إلى مُرحِّلك فقد تُمنَع من الدخول. أدخِل هنا عنوان URL لعقدة كاملة تعمل حتى يتمكّن التطبيق من الاتصال."},
    hi:{"footer":"NADO लाइट-माइनर · चेन पूरे (फुल) नोड्स पर रहती है; यह पेज सिर्फ कीज़ बनाता है, रजिस्टर करता है, और आपकी प्रेज़ेंस लीज़ को रिन्यू करता है। आपका इनाम आपके एड्रेस पर इसलिए आता है क्योंकि एक रिले वह ब्लॉक बनाता है जो उसे क्रेडिट करता है।","tip.present":"PRESENT — आपके पास एक वैध प्रेज़ेंस लीज़ है (एक हालिया PoSW पुनःप्रमाणन/recert), इसलिए आप अभी ओपन-लेन ब्लॉक जीतने के लिए ELIGIBLE (पात्र) हैं। वॉलेट लीज़ के खत्म होने से पहले उसे अपने आप रिन्यू कर देता है; अगर यह रुक जाए, तो प्रेज़ेंस खत्म हो जाती है और जब तक यह दोबारा शुरू न हो, तब तक आपकी कमाई रुक जाती है।","tip.locked":"MINING WHILE LOCKED — आपकी PoSW प्रेज़ेंस लीज़ ऑन-चेन वैध बनी रहती है, इसलिए लॉक या स्लीप में पड़ा फोन तब तक माइनिंग करता रहता है जब तक यह खत्म नहीं हो जाती। लीज़ को रिन्यू करने (एक नया पोस्ट-क्वांटम PoSW पुनःप्रमाणन/recert) के लिए आपका फोन एक्टिव होना जरूरी है, इसलिए इसके खत्म होने से पहले ऐप दोबारा खोलें — यह करीब एक सेकंड में, अपने आप रिन्यू हो जाती है। (ट्रांज़ैक्शन भेजने के लिए उस समय आपका फोन अनलॉक होना हमेशा जरूरी है।)","unlock.relayToggle":"रिले नोड बदलें","unlock.relayNote":"अगर आपका रिले पहुंच से बाहर है तो आप लॉक-आउट हो सकते हैं। यहां एक चालू फुल-नोड URL सेट करें ताकि ऐप कनेक्ट हो सके।"},
    tr:{"footer":"NADO hafif madenci · zincir tam düğümlerde kalır; bu sayfa yalnızca anahtar üretir, sizi kaydeder ve mevcudiyet kiranızı yeniler. Ödülünüz adresinize ulaşır çünkü bir aktarıcı, onu adresinize yazan bloğu oluşturur.","tip.present":"MEVCUT — geçerli bir mevcudiyet kiranız var (yakın zamanlı bir PoSW yeniden onayı), bu yüzden şu anda açık şerit bloklarını kazanmaya UYGUNSUNUZ. Cüzdan, kira sona ermeden önce onu otomatik olarak yeniler; durursa mevcudiyetiniz düşer ve yeniden başlayana kadar kazanmayı durdurursunuz.","tip.locked":"KİLİTLİYKEN MADENCİLİK — PoSW mevcudiyet kiranız zincir üzerinde geçerli kalır, bu yüzden kilitli/uyku modundaki bir telefon, kira sona erene kadar madenciliğe devam eder. Kirayı yenilemek (yeni bir post-kuantum PoSW yeniden onayı) telefonunuzun etkin olmasını gerektirir, bu yüzden bu süre dolmadan önce uygulamayı yeniden açın — yaklaşık bir saniyede, otomatik olarak yenilenir. (İşlem göndermek, o an telefonunuzun kilidinin açık olmasını her zaman gerektirir.)","unlock.relayToggle":"Aktarıcı düğümünü değiştir","unlock.relayNote":"Aktarıcınıza ulaşılamıyorsa erişiminiz kesilebilir. Uygulamanın bağlanabilmesi için buraya çalışan bir tam düğüm URL'si girin."},
    id:{"footer":"NADO light-miner · rantai tetap berjalan di full node; halaman ini hanya membuat kunci, mendaftar, dan memperbarui sewa kehadiran (presence lease) Anda. Hadiah Anda masuk ke alamat Anda karena ada relay yang membangun blok yang mengkreditkannya.","tip.present":"HADIR — Anda memegang sewa kehadiran yang valid (resertifikasi PoSW terbaru), jadi saat ini Anda BERHAK memenangkan blok jalur-terbuka. Dompet memperbarui sewa itu secara otomatis sebelum kedaluwarsa; jika berhenti, kehadiran akan kedaluwarsa dan Anda berhenti memperoleh hadiah sampai berjalan kembali.","tip.locked":"MENAMBANG SAAT TERKUNCI — sewa kehadiran PoSW Anda tetap valid di rantai, jadi ponsel yang terkunci/tertidur akan terus menambang sampai sewa itu kedaluwarsa. Memperbarui sewa (resertifikasi PoSW pasca-kuantum yang baru) memerlukan ponsel Anda dalam keadaan aktif, jadi buka kembali aplikasi sebelum masa ini habis — pembaruan berlangsung sekitar satu detik, secara otomatis. (Mengirim transaksi selalu memerlukan ponsel Anda tidak terkunci pada saat itu.)","unlock.relayToggle":"Ganti node relay","unlock.relayNote":"Jika relay Anda tidak dapat dijangkau, Anda bisa terkunci dari akses. Atur URL full-node yang berfungsi di sini agar aplikasi dapat terhubung."},
    vi:{"footer":"Trình đào nhẹ NADO · chuỗi được lưu trên các full node; trang này chỉ tạo khóa, đăng ký và gia hạn hợp đồng hiện diện của bạn. Phần thưởng về đúng địa chỉ của bạn vì có một relay dựng khối ghi có cho địa chỉ đó.","tip.present":"ĐANG HIỆN DIỆN — bạn đang giữ một hợp đồng hiện diện hợp lệ (một lần tái chứng thực PoSW gần đây), nên hiện tại bạn ĐỦ ĐIỀU KIỆN để giành các khối làn mở. Ví tự động gia hạn hợp đồng trước khi nó hết hạn; nếu việc này dừng lại, hiện diện sẽ hết hạn và bạn ngừng kiếm thưởng cho đến khi nó tiếp tục.","tip.locked":"ĐÀO KHI KHÓA MÁY — hợp đồng hiện diện PoSW của bạn vẫn còn hiệu lực trên chuỗi, nên điện thoại đã khóa/đang ngủ vẫn tiếp tục đào cho đến khi hợp đồng hết hạn. Việc gia hạn hợp đồng (một lần tái chứng thực PoSW hậu lượng tử mới) cần điện thoại đang hoạt động, vì vậy hãy mở lại ứng dụng trước khi nó hết hạn — quá trình gia hạn diễn ra tự động trong khoảng một giây. (Gửi giao dịch thì luôn cần mở khóa điện thoại ngay tại thời điểm đó.)","unlock.relayToggle":"Đổi node relay","unlock.relayNote":"Nếu relay của bạn không kết nối được, bạn có thể bị khóa ngoài. Hãy đặt một URL full-node hoạt động tốt ở đây để ứng dụng có thể kết nối."}
  };
  for (const l in T45) Object.assign(T[l] = T[l] || {}, T45[l]);

  // T46: Multisig-tab strings (opt-in M-of-N shared accounts, ops/multisig_ops.py) — {m}/{n}/{a}/{b}/{have}/{need} placeholders kept.
  const T46 = {
    en:{"tab.multisig":"Multisig","msig.title":"Multisig","msig.pill":"shared M-of-N accounts","msig.intro":"A shared account that needs M of N member signatures to spend — for couples, teams, escrow or two-device security. The address is derived from the member list + threshold; fund it like any address. One member creates a proposal, co-signers each add a signature (pass the proposal text by any channel — chat, email, QR), and anyone submits it once enough have signed.","msig.members":"Member addresses (one per line)","msig.threshold":"Signatures required to spend (M)","btn.msigDerive":"Derive shared address","msig.address":"Shared address","msig.balance":"Balance:","msig.proposeTitle":"Propose a spend from the shared account","btn.msigPropose":"Create proposal + sign","msig.cosignTitle":"Proposal — co-sign & submit","msig.cosignIntro":"Paste a proposal you received here (or create one above). Add your signature and pass it on — or submit it once it has enough signatures. Proposals expire if not submitted within ~50 minutes of creation.","btn.msigSign":"Add my signature","btn.msigSubmit":"Submit","msig.badJson":"This is not a valid proposal ({m}).","msig.badCount":"Enter 2–16 distinct member addresses.","msig.badMember":"Not a valid ndo… address: {a}","msig.badThreshold":"Signatures required must be between 1 and the number of members.","msig.notProposal":"This is not a multisig proposal.","msig.txidMismatch":"Proposal id does not match its contents — do not sign it.","msig.senderMismatch":"Proposal sender does not match its member list — do not sign it.","msig.derived":"{m}-of-{n} account ready — fund it like any address.","msig.aliasMissing":"That alias isn't registered.","msig.insufficient":"The shared account holds {b} NADO — not enough for this amount + fee.","msig.proposed":"Proposal created below — copy it and pass it to your co-signers.","msig.stFrom":"From {a}","msig.stTo":"to {a}","msig.stSigs":"signatures {have}/{need}","msig.stExpiry":"valid until block {b}","msig.stReady":"Ready to submit ✓","msig.stWaiting":"You signed — pass it to the next co-signer.","msig.stYourTurn":"Your signature is needed.","msig.stNotMember":"This wallet is not a member of the account.","msig.pasteFirst":"Paste a proposal first.","msig.signedOk":"Signature added ✓ — copy the proposal and pass it on (or submit if it's ready).","msig.alreadySigned":"Nothing to add — you already signed, or this wallet is not a member.","msig.dlgTitle":"Submit multisig transfer","msig.dlgSigs":"Signatures","msig.submitted":"Submitted ✓ — the transfer settles on-chain in a few blocks.","msig.copied":"Proposal copied — send it to a co-signer."},
    cs:{"tab.multisig":"Multisig","msig.title":"Multisig","msig.pill":"sdílené účty M z N","msig.intro":"Sdílený účet, který k utracení vyžaduje M z N podpisů členů — pro páry, týmy, úschovu nebo zabezpečení dvěma zařízeními. Adresa se odvozuje ze seznamu členů a prahu; pošlete na ni prostředky jako na běžnou adresu. Jeden člen vytvoří návrh, spolupodepisující postupně přidají podpis (text návrhu předávejte libovolným kanálem — chat, e-mail, QR) a jakmile je podpisů dost, kdokoli jej odešle.","msig.members":"Adresy členů (jedna na řádek)","msig.threshold":"Počet podpisů k utracení (M)","btn.msigDerive":"Odvodit sdílenou adresu","msig.address":"Sdílená adresa","msig.balance":"Zůstatek:","msig.proposeTitle":"Navrhnout platbu ze sdíleného účtu","btn.msigPropose":"Vytvořit návrh + podepsat","msig.cosignTitle":"Návrh — spolupodepsat a odeslat","msig.cosignIntro":"Sem vložte návrh, který jste obdrželi (nebo jej vytvořte výše). Přidejte svůj podpis a pošlete jej dál — nebo jej odešlete, jakmile má dost podpisů. Neodeslané návrhy vyprší zhruba 50 minut po vytvoření.","btn.msigSign":"Přidat můj podpis","btn.msigSubmit":"Odeslat","msig.badJson":"Toto není platný návrh ({m}).","msig.badCount":"Zadejte 2–16 různých adres členů.","msig.badMember":"Neplatná adresa ndo…: {a}","msig.badThreshold":"Počet požadovaných podpisů musí být mezi 1 a počtem členů.","msig.notProposal":"Toto není multisig návrh.","msig.txidMismatch":"Id návrhu neodpovídá jeho obsahu — nepodepisujte jej.","msig.senderMismatch":"Odesílatel návrhu neodpovídá seznamu členů — nepodepisujte jej.","msig.derived":"Účet {m} z {n} je připraven — pošlete na něj prostředky jako na běžnou adresu.","msig.aliasMissing":"Tento alias není registrován.","msig.insufficient":"Sdílený účet má {b} NADO — na částku + poplatek to nestačí.","msig.proposed":"Návrh je vytvořen níže — zkopírujte jej a předejte spolupodepisujícím.","msig.stFrom":"Od {a}","msig.stTo":"pro {a}","msig.stSigs":"podpisy {have}/{need}","msig.stExpiry":"platí do bloku {b}","msig.stReady":"Připraveno k odeslání ✓","msig.stWaiting":"Podepsáno — předejte návrh dalšímu spolupodepisujícímu.","msig.stYourTurn":"Je potřeba váš podpis.","msig.stNotMember":"Tato peněženka není členem účtu.","msig.pasteFirst":"Nejprve vložte návrh.","msig.signedOk":"Podpis přidán ✓ — zkopírujte návrh a pošlete jej dál (nebo odešlete, je-li připraven).","msig.alreadySigned":"Není co přidat — už jste podepsali, nebo tato peněženka není členem.","msig.dlgTitle":"Odeslat multisig převod","msig.dlgSigs":"Podpisy","msig.submitted":"Odesláno ✓ — převod se na řetězci usadí během několika bloků.","msig.copied":"Návrh zkopírován — pošlete jej spolupodepisujícímu."},
    es:{"tab.multisig":"Multifirma","msig.title":"Multifirma","msig.pill":"cuentas compartidas M de N","msig.intro":"Una cuenta compartida que necesita M de N firmas de sus miembros para gastar — para parejas, equipos, custodia o seguridad con dos dispositivos. La dirección se deriva de la lista de miembros + umbral; fóndala como cualquier dirección. Un miembro crea una propuesta, cada cofirmante añade su firma (pasa el texto de la propuesta por cualquier canal — chat, correo, QR) y cualquiera la envía cuando haya firmas suficientes.","msig.members":"Direcciones de los miembros (una por línea)","msig.threshold":"Firmas necesarias para gastar (M)","btn.msigDerive":"Derivar dirección compartida","msig.address":"Dirección compartida","msig.balance":"Saldo:","msig.proposeTitle":"Proponer un gasto desde la cuenta compartida","btn.msigPropose":"Crear propuesta + firmar","msig.cosignTitle":"Propuesta — cofirmar y enviar","msig.cosignIntro":"Pega aquí una propuesta recibida (o crea una arriba). Añade tu firma y pásala — o envíala cuando tenga firmas suficientes. Las propuestas caducan si no se envían en ~50 minutos desde su creación.","btn.msigSign":"Añadir mi firma","btn.msigSubmit":"Enviar","msig.badJson":"Esto no es una propuesta válida ({m}).","msig.badCount":"Introduce 2–16 direcciones de miembros distintas.","msig.badMember":"Dirección ndo… no válida: {a}","msig.badThreshold":"Las firmas requeridas deben estar entre 1 y el número de miembros.","msig.notProposal":"Esto no es una propuesta multifirma.","msig.txidMismatch":"El id de la propuesta no coincide con su contenido — no la firmes.","msig.senderMismatch":"El remitente de la propuesta no coincide con su lista de miembros — no la firmes.","msig.derived":"Cuenta {m} de {n} lista — fóndala como cualquier dirección.","msig.aliasMissing":"Ese alias no está registrado.","msig.insufficient":"La cuenta compartida tiene {b} NADO — no alcanza para este importe + comisión.","msig.proposed":"Propuesta creada abajo — cópiala y pásala a tus cofirmantes.","msig.stFrom":"De {a}","msig.stTo":"a {a}","msig.stSigs":"firmas {have}/{need}","msig.stExpiry":"válida hasta el bloque {b}","msig.stReady":"Lista para enviar ✓","msig.stWaiting":"Ya firmaste — pásala al siguiente cofirmante.","msig.stYourTurn":"Se necesita tu firma.","msig.stNotMember":"Esta wallet no es miembro de la cuenta.","msig.pasteFirst":"Pega primero una propuesta.","msig.signedOk":"Firma añadida ✓ — copia la propuesta y pásala (o envíala si está lista).","msig.alreadySigned":"Nada que añadir — ya firmaste, o esta wallet no es miembro.","msig.dlgTitle":"Enviar transferencia multifirma","msig.dlgSigs":"Firmas","msig.submitted":"Enviado ✓ — la transferencia se asienta en la cadena en unos bloques.","msig.copied":"Propuesta copiada — envíasela a un cofirmante."},
    pt:{"tab.multisig":"Multiassinatura","msig.title":"Multiassinatura","msig.pill":"contas compartilhadas M de N","msig.intro":"Uma conta compartilhada que exige M de N assinaturas dos membros para gastar — para casais, equipes, custódia ou segurança com dois dispositivos. O endereço deriva da lista de membros + limiar; deposite nela como em qualquer endereço. Um membro cria uma proposta, cada cossignatário adiciona sua assinatura (passe o texto da proposta por qualquer canal — chat, e-mail, QR) e qualquer um a envia quando houver assinaturas suficientes.","msig.members":"Endereços dos membros (um por linha)","msig.threshold":"Assinaturas necessárias para gastar (M)","btn.msigDerive":"Derivar endereço compartilhado","msig.address":"Endereço compartilhado","msig.balance":"Saldo:","msig.proposeTitle":"Propor um gasto da conta compartilhada","btn.msigPropose":"Criar proposta + assinar","msig.cosignTitle":"Proposta — cossinar e enviar","msig.cosignIntro":"Cole aqui uma proposta recebida (ou crie uma acima). Adicione sua assinatura e repasse — ou envie quando tiver assinaturas suficientes. Propostas expiram se não forem enviadas em ~50 minutos após a criação.","btn.msigSign":"Adicionar minha assinatura","btn.msigSubmit":"Enviar","msig.badJson":"Isto não é uma proposta válida ({m}).","msig.badCount":"Insira 2–16 endereços de membros distintos.","msig.badMember":"Endereço ndo… inválido: {a}","msig.badThreshold":"As assinaturas exigidas devem estar entre 1 e o número de membros.","msig.notProposal":"Isto não é uma proposta multiassinatura.","msig.txidMismatch":"O id da proposta não corresponde ao seu conteúdo — não a assine.","msig.senderMismatch":"O remetente da proposta não corresponde à lista de membros — não a assine.","msig.derived":"Conta {m} de {n} pronta — deposite nela como em qualquer endereço.","msig.aliasMissing":"Esse alias não está registrado.","msig.insufficient":"A conta compartilhada tem {b} NADO — insuficiente para este valor + taxa.","msig.proposed":"Proposta criada abaixo — copie e repasse aos seus cossignatários.","msig.stFrom":"De {a}","msig.stTo":"para {a}","msig.stSigs":"assinaturas {have}/{need}","msig.stExpiry":"válida até o bloco {b}","msig.stReady":"Pronta para enviar ✓","msig.stWaiting":"Você assinou — repasse ao próximo cossignatário.","msig.stYourTurn":"Sua assinatura é necessária.","msig.stNotMember":"Esta carteira não é membro da conta.","msig.pasteFirst":"Cole uma proposta primeiro.","msig.signedOk":"Assinatura adicionada ✓ — copie a proposta e repasse (ou envie se estiver pronta).","msig.alreadySigned":"Nada a adicionar — você já assinou, ou esta carteira não é membro.","msig.dlgTitle":"Enviar transferência multiassinatura","msig.dlgSigs":"Assinaturas","msig.submitted":"Enviado ✓ — a transferência é liquidada na cadeia em alguns blocos.","msig.copied":"Proposta copiada — envie a um cossignatário."},
    fr:{"tab.multisig":"Multisig","msig.title":"Multisig","msig.pill":"comptes partagés M parmi N","msig.intro":"Un compte partagé qui exige M signatures parmi N membres pour dépenser — pour les couples, les équipes, un séquestre ou une sécurité à deux appareils. L'adresse est dérivée de la liste des membres + du seuil ; approvisionnez-la comme n'importe quelle adresse. Un membre crée une proposition, chaque cosignataire ajoute sa signature (transmettez le texte par n'importe quel canal — chat, e-mail, QR), et n'importe qui la soumet une fois assez de signatures réunies.","msig.members":"Adresses des membres (une par ligne)","msig.threshold":"Signatures requises pour dépenser (M)","btn.msigDerive":"Dériver l'adresse partagée","msig.address":"Adresse partagée","msig.balance":"Solde :","msig.proposeTitle":"Proposer une dépense depuis le compte partagé","btn.msigPropose":"Créer la proposition + signer","msig.cosignTitle":"Proposition — cosigner et soumettre","msig.cosignIntro":"Collez ici une proposition reçue (ou créez-en une ci-dessus). Ajoutez votre signature et transmettez-la — ou soumettez-la dès qu'elle a assez de signatures. Une proposition expire si elle n'est pas soumise dans les ~50 minutes suivant sa création.","btn.msigSign":"Ajouter ma signature","btn.msigSubmit":"Soumettre","msig.badJson":"Ceci n'est pas une proposition valide ({m}).","msig.badCount":"Saisissez 2–16 adresses de membres distinctes.","msig.badMember":"Adresse ndo… non valide : {a}","msig.badThreshold":"Le nombre de signatures requises doit être entre 1 et le nombre de membres.","msig.notProposal":"Ceci n'est pas une proposition multisig.","msig.txidMismatch":"L'id de la proposition ne correspond pas à son contenu — ne la signez pas.","msig.senderMismatch":"L'expéditeur de la proposition ne correspond pas à sa liste de membres — ne la signez pas.","msig.derived":"Compte {m} parmi {n} prêt — approvisionnez-le comme n'importe quelle adresse.","msig.aliasMissing":"Cet alias n'est pas enregistré.","msig.insufficient":"Le compte partagé détient {b} NADO — insuffisant pour ce montant + les frais.","msig.proposed":"Proposition créée ci-dessous — copiez-la et transmettez-la à vos cosignataires.","msig.stFrom":"De {a}","msig.stTo":"vers {a}","msig.stSigs":"signatures {have}/{need}","msig.stExpiry":"valide jusqu'au bloc {b}","msig.stReady":"Prête à soumettre ✓","msig.stWaiting":"Vous avez signé — transmettez-la au cosignataire suivant.","msig.stYourTurn":"Votre signature est requise.","msig.stNotMember":"Ce portefeuille n'est pas membre du compte.","msig.pasteFirst":"Collez d'abord une proposition.","msig.signedOk":"Signature ajoutée ✓ — copiez la proposition et transmettez-la (ou soumettez-la si elle est prête).","msig.alreadySigned":"Rien à ajouter — vous avez déjà signé, ou ce portefeuille n'est pas membre.","msig.dlgTitle":"Soumettre le transfert multisig","msig.dlgSigs":"Signatures","msig.submitted":"Soumis ✓ — le transfert est réglé on-chain en quelques blocs.","msig.copied":"Proposition copiée — envoyez-la à un cosignataire."},
    de:{"tab.multisig":"Multisig","msig.title":"Multisig","msig.pill":"gemeinsame M-von-N-Konten","msig.intro":"Ein gemeinsames Konto, das zum Ausgeben M von N Mitglieds-Signaturen braucht — für Paare, Teams, Treuhand oder Zwei-Geräte-Sicherheit. Die Adresse wird aus Mitgliederliste + Schwelle abgeleitet; Guthaben schickst du wie an jede andere Adresse. Ein Mitglied erstellt einen Vorschlag, Mitunterzeichner fügen je eine Signatur hinzu (den Vorschlagstext über einen beliebigen Kanal weitergeben — Chat, E-Mail, QR), und sobald genug signiert haben, reicht ihn irgendjemand ein.","msig.members":"Mitglieder-Adressen (eine pro Zeile)","msig.threshold":"Zum Ausgeben nötige Signaturen (M)","btn.msigDerive":"Gemeinsame Adresse ableiten","msig.address":"Gemeinsame Adresse","msig.balance":"Guthaben:","msig.proposeTitle":"Eine Ausgabe vom gemeinsamen Konto vorschlagen","btn.msigPropose":"Vorschlag erstellen + signieren","msig.cosignTitle":"Vorschlag — mitunterzeichnen & einreichen","msig.cosignIntro":"Füge hier einen erhaltenen Vorschlag ein (oder erstelle oben einen). Füge deine Signatur hinzu und gib ihn weiter — oder reiche ihn ein, sobald genug Signaturen vorliegen. Vorschläge verfallen, wenn sie nicht innerhalb von ~50 Minuten eingereicht werden.","btn.msigSign":"Meine Signatur hinzufügen","btn.msigSubmit":"Einreichen","msig.badJson":"Das ist kein gültiger Vorschlag ({m}).","msig.badCount":"Gib 2–16 verschiedene Mitglieder-Adressen ein.","msig.badMember":"Keine gültige ndo…-Adresse: {a}","msig.badThreshold":"Die nötigen Signaturen müssen zwischen 1 und der Mitgliederzahl liegen.","msig.notProposal":"Das ist kein Multisig-Vorschlag.","msig.txidMismatch":"Die Vorschlags-Id passt nicht zum Inhalt — nicht signieren.","msig.senderMismatch":"Der Absender des Vorschlags passt nicht zur Mitgliederliste — nicht signieren.","msig.derived":"{m}-von-{n}-Konto bereit — Guthaben wie an jede Adresse senden.","msig.aliasMissing":"Dieser Alias ist nicht registriert.","msig.insufficient":"Das gemeinsame Konto hält {b} NADO — zu wenig für Betrag + Gebühr.","msig.proposed":"Vorschlag unten erstellt — kopiere ihn und gib ihn an deine Mitunterzeichner weiter.","msig.stFrom":"Von {a}","msig.stTo":"an {a}","msig.stSigs":"Signaturen {have}/{need}","msig.stExpiry":"gültig bis Block {b}","msig.stReady":"Bereit zum Einreichen ✓","msig.stWaiting":"Du hast signiert — gib ihn an den nächsten Mitunterzeichner weiter.","msig.stYourTurn":"Deine Signatur wird benötigt.","msig.stNotMember":"Diese Wallet ist kein Mitglied des Kontos.","msig.pasteFirst":"Füge zuerst einen Vorschlag ein.","msig.signedOk":"Signatur hinzugefügt ✓ — Vorschlag kopieren und weitergeben (oder einreichen, wenn er bereit ist).","msig.alreadySigned":"Nichts hinzuzufügen — du hast schon signiert, oder diese Wallet ist kein Mitglied.","msig.dlgTitle":"Multisig-Überweisung einreichen","msig.dlgSigs":"Signaturen","msig.submitted":"Eingereicht ✓ — die Überweisung wird in wenigen Blöcken on-chain verbucht.","msig.copied":"Vorschlag kopiert — sende ihn an einen Mitunterzeichner."},
    it:{"tab.multisig":"Multifirma","msig.title":"Multifirma","msig.pill":"conti condivisi M di N","msig.intro":"Un conto condiviso che richiede M firme su N membri per spendere — per coppie, team, depositi in garanzia o sicurezza a due dispositivi. L'indirizzo deriva dall'elenco dei membri + la soglia; ricaricalo come qualsiasi indirizzo. Un membro crea una proposta, ogni cofirmatario aggiunge la propria firma (passa il testo della proposta con qualunque canale — chat, email, QR) e chiunque la invia quando le firme bastano.","msig.members":"Indirizzi dei membri (uno per riga)","msig.threshold":"Firme richieste per spendere (M)","btn.msigDerive":"Deriva indirizzo condiviso","msig.address":"Indirizzo condiviso","msig.balance":"Saldo:","msig.proposeTitle":"Proponi una spesa dal conto condiviso","btn.msigPropose":"Crea proposta + firma","msig.cosignTitle":"Proposta — cofirma e invia","msig.cosignIntro":"Incolla qui una proposta ricevuta (o creane una sopra). Aggiungi la tua firma e passala — oppure inviala quando ha abbastanza firme. Le proposte scadono se non inviate entro ~50 minuti dalla creazione.","btn.msigSign":"Aggiungi la mia firma","btn.msigSubmit":"Invia","msig.badJson":"Questa non è una proposta valida ({m}).","msig.badCount":"Inserisci 2–16 indirizzi membri distinti.","msig.badMember":"Indirizzo ndo… non valido: {a}","msig.badThreshold":"Le firme richieste devono essere tra 1 e il numero di membri.","msig.notProposal":"Questa non è una proposta multifirma.","msig.txidMismatch":"L'id della proposta non corrisponde al contenuto — non firmarla.","msig.senderMismatch":"Il mittente della proposta non corrisponde all'elenco membri — non firmarla.","msig.derived":"Conto {m} di {n} pronto — ricaricalo come qualsiasi indirizzo.","msig.aliasMissing":"Quell'alias non è registrato.","msig.insufficient":"Il conto condiviso ha {b} NADO — non basta per importo + commissione.","msig.proposed":"Proposta creata qui sotto — copiala e passala ai tuoi cofirmatari.","msig.stFrom":"Da {a}","msig.stTo":"a {a}","msig.stSigs":"firme {have}/{need}","msig.stExpiry":"valida fino al blocco {b}","msig.stReady":"Pronta all'invio ✓","msig.stWaiting":"Hai firmato — passala al prossimo cofirmatario.","msig.stYourTurn":"Serve la tua firma.","msig.stNotMember":"Questo wallet non è membro del conto.","msig.pasteFirst":"Prima incolla una proposta.","msig.signedOk":"Firma aggiunta ✓ — copia la proposta e passala (o inviala se è pronta).","msig.alreadySigned":"Niente da aggiungere — hai già firmato, o questo wallet non è membro.","msig.dlgTitle":"Invia trasferimento multifirma","msig.dlgSigs":"Firme","msig.submitted":"Inviato ✓ — il trasferimento si regola on-chain in pochi blocchi.","msig.copied":"Proposta copiata — mandala a un cofirmatario."},
    ru:{"tab.multisig":"Мультиподпись","msig.title":"Мультиподпись","msig.pill":"общие счета M из N","msig.intro":"Общий счёт, для траты с которого нужно M из N подписей участников — для пар, команд, эскроу или защиты двумя устройствами. Адрес выводится из списка участников и порога; пополняйте его как обычный адрес. Один участник создаёт предложение, соподписанты добавляют по подписи (текст предложения передавайте любым каналом — чат, почта, QR), и как только подписей достаточно, любой его отправляет.","msig.members":"Адреса участников (по одному в строке)","msig.threshold":"Подписей для траты (M)","btn.msigDerive":"Вывести общий адрес","msig.address":"Общий адрес","msig.balance":"Баланс:","msig.proposeTitle":"Предложить трату с общего счёта","btn.msigPropose":"Создать предложение + подписать","msig.cosignTitle":"Предложение — соподписать и отправить","msig.cosignIntro":"Вставьте сюда полученное предложение (или создайте выше). Добавьте свою подпись и передайте дальше — или отправьте, когда подписей достаточно. Неотправленные предложения истекают примерно через 50 минут после создания.","btn.msigSign":"Добавить мою подпись","btn.msigSubmit":"Отправить","msig.badJson":"Это не корректное предложение ({m}).","msig.badCount":"Введите 2–16 различных адресов участников.","msig.badMember":"Некорректный адрес ndo…: {a}","msig.badThreshold":"Число требуемых подписей должно быть от 1 до числа участников.","msig.notProposal":"Это не предложение мультиподписи.","msig.txidMismatch":"Id предложения не совпадает с его содержимым — не подписывайте.","msig.senderMismatch":"Отправитель предложения не совпадает со списком участников — не подписывайте.","msig.derived":"Счёт {m} из {n} готов — пополняйте его как обычный адрес.","msig.aliasMissing":"Этот псевдоним не зарегистрирован.","msig.insufficient":"На общем счёте {b} NADO — недостаточно для суммы + комиссии.","msig.proposed":"Предложение создано ниже — скопируйте и передайте соподписантам.","msig.stFrom":"От {a}","msig.stTo":"кому {a}","msig.stSigs":"подписей {have}/{need}","msig.stExpiry":"действует до блока {b}","msig.stReady":"Готово к отправке ✓","msig.stWaiting":"Вы подписали — передайте следующему соподписанту.","msig.stYourTurn":"Нужна ваша подпись.","msig.stNotMember":"Этот кошелёк не является участником счёта.","msig.pasteFirst":"Сначала вставьте предложение.","msig.signedOk":"Подпись добавлена ✓ — скопируйте предложение и передайте дальше (или отправьте, если готово).","msig.alreadySigned":"Нечего добавить — вы уже подписали, или этот кошелёк не участник.","msig.dlgTitle":"Отправить мультиподписной перевод","msig.dlgSigs":"Подписи","msig.submitted":"Отправлено ✓ — перевод зафиксируется в блокчейне через несколько блоков.","msig.copied":"Предложение скопировано — отправьте его соподписанту."},
    zh:{"tab.multisig":"多重签名","msig.title":"多重签名","msig.pill":"M-of-N 共享账户","msig.intro":"一个需要 N 名成员中 M 个签名才能支出的共享账户——适合伴侣、团队、托管或双设备安全。地址由成员列表 + 阈值推导；像普通地址一样充值即可。一名成员创建提案，各共同签名者依次添加签名（提案文本可通过任何渠道传递——聊天、邮件、二维码），签名足够后任何人都可提交。","msig.members":"成员地址（每行一个）","msig.threshold":"支出所需签名数（M）","btn.msigDerive":"推导共享地址","msig.address":"共享地址","msig.balance":"余额：","msig.proposeTitle":"从共享账户发起支出提案","btn.msigPropose":"创建提案 + 签名","msig.cosignTitle":"提案——共同签名并提交","msig.cosignIntro":"在此粘贴收到的提案（或在上方创建）。添加你的签名后传给下一位——或在签名足够时提交。提案创建后约 50 分钟内未提交即失效。","btn.msigSign":"添加我的签名","btn.msigSubmit":"提交","msig.badJson":"这不是有效的提案（{m}）。","msig.badCount":"请输入 2–16 个不同的成员地址。","msig.badMember":"不是有效的 ndo… 地址：{a}","msig.badThreshold":"所需签名数必须在 1 与成员数之间。","msig.notProposal":"这不是多重签名提案。","msig.txidMismatch":"提案 id 与其内容不符——请勿签名。","msig.senderMismatch":"提案发送方与其成员列表不符——请勿签名。","msig.derived":"{m}/{n} 账户已就绪——像普通地址一样充值即可。","msig.aliasMissing":"该别名未注册。","msig.insufficient":"共享账户余额为 {b} NADO——不足以支付此金额 + 手续费。","msig.proposed":"提案已在下方创建——复制后传给你的共同签名者。","msig.stFrom":"从 {a}","msig.stTo":"至 {a}","msig.stSigs":"签名 {have}/{need}","msig.stExpiry":"有效期至区块 {b}","msig.stReady":"可以提交 ✓","msig.stWaiting":"你已签名——请传给下一位共同签名者。","msig.stYourTurn":"需要你的签名。","msig.stNotMember":"此钱包不是该账户的成员。","msig.pasteFirst":"请先粘贴提案。","msig.signedOk":"签名已添加 ✓——复制提案并传递（或在就绪时提交）。","msig.alreadySigned":"无需添加——你已签名，或此钱包不是成员。","msig.dlgTitle":"提交多重签名转账","msig.dlgSigs":"签名","msig.submitted":"已提交 ✓——转账将在几个区块内上链结算。","msig.copied":"提案已复制——发送给一位共同签名者。"},
    ja:{"tab.multisig":"マルチシグ","msig.title":"マルチシグ","msig.pill":"M-of-N 共有アカウント","msig.intro":"N 人のメンバーのうち M 人の署名がないと支出できない共有アカウントです。夫婦・チーム・エスクロー・2 台持ちのセキュリティに。アドレスはメンバー一覧としきい値から導出され、普通のアドレスと同じように入金できます。メンバーの一人が提案を作成し、共同署名者が順に署名を追加(提案テキストはチャット・メール・QR など任意の経路で受け渡し)、署名が揃ったら誰でも送信できます。","msig.members":"メンバーのアドレス(1 行に 1 つ)","msig.threshold":"支出に必要な署名数(M)","btn.msigDerive":"共有アドレスを導出","msig.address":"共有アドレス","msig.balance":"残高:","msig.proposeTitle":"共有アカウントから支出を提案","btn.msigPropose":"提案を作成 + 署名","msig.cosignTitle":"提案 — 共同署名して送信","msig.cosignIntro":"受け取った提案をここに貼り付けます(または上で作成)。署名を追加して次へ回すか、署名が揃ったら送信してください。提案は作成から約 50 分以内に送信しないと失効します。","btn.msigSign":"自分の署名を追加","btn.msigSubmit":"送信","msig.badJson":"有効な提案ではありません({m})。","msig.badCount":"2–16 件の異なるメンバーアドレスを入力してください。","msig.badMember":"有効な ndo… アドレスではありません: {a}","msig.badThreshold":"必要署名数は 1 からメンバー数までにしてください。","msig.notProposal":"これはマルチシグ提案ではありません。","msig.txidMismatch":"提案 id が内容と一致しません — 署名しないでください。","msig.senderMismatch":"提案の送信元がメンバー一覧と一致しません — 署名しないでください。","msig.derived":"{m}-of-{n} アカウントの準備ができました — 普通のアドレスと同様に入金できます。","msig.aliasMissing":"そのエイリアスは登録されていません。","msig.insufficient":"共有アカウントの残高は {b} NADO — この金額 + 手数料には足りません。","msig.proposed":"下に提案を作成しました — コピーして共同署名者に渡してください。","msig.stFrom":"送信元 {a}","msig.stTo":"宛先 {a}","msig.stSigs":"署名 {have}/{need}","msig.stExpiry":"ブロック {b} まで有効","msig.stReady":"送信可能 ✓","msig.stWaiting":"署名済み — 次の共同署名者へ回してください。","msig.stYourTurn":"あなたの署名が必要です。","msig.stNotMember":"このウォレットはアカウントのメンバーではありません。","msig.pasteFirst":"まず提案を貼り付けてください。","msig.signedOk":"署名を追加しました ✓ — 提案をコピーして回してください(揃っていれば送信)。","msig.alreadySigned":"追加なし — 署名済みか、このウォレットはメンバーではありません。","msig.dlgTitle":"マルチシグ送金を送信","msig.dlgSigs":"署名","msig.submitted":"送信しました ✓ — 数ブロック以内にオンチェーンで確定します。","msig.copied":"提案をコピーしました — 共同署名者に送ってください。"},
    ko:{"tab.multisig":"멀티시그","msig.title":"멀티시그","msig.pill":"M-of-N 공유 계정","msig.intro":"N명의 구성원 중 M명의 서명이 있어야 지출할 수 있는 공유 계정입니다 — 커플, 팀, 에스크로, 두 기기 보안용. 주소는 구성원 목록 + 임계값에서 파생되며, 일반 주소처럼 입금하면 됩니다. 한 구성원이 제안을 만들고, 공동 서명자들이 서명을 추가한 뒤(제안 텍스트는 채팅·이메일·QR 등 아무 경로로 전달), 서명이 충분해지면 누구든 제출할 수 있습니다.","msig.members":"구성원 주소 (한 줄에 하나)","msig.threshold":"지출에 필요한 서명 수 (M)","btn.msigDerive":"공유 주소 파생","msig.address":"공유 주소","msig.balance":"잔액:","msig.proposeTitle":"공유 계정에서 지출 제안","btn.msigPropose":"제안 생성 + 서명","msig.cosignTitle":"제안 — 공동 서명 및 제출","msig.cosignIntro":"받은 제안을 여기에 붙여넣으세요(또는 위에서 생성). 서명을 추가해 전달하거나, 서명이 충분하면 제출하세요. 제안은 생성 후 약 50분 안에 제출하지 않으면 만료됩니다.","btn.msigSign":"내 서명 추가","btn.msigSubmit":"제출","msig.badJson":"유효한 제안이 아닙니다({m}).","msig.badCount":"서로 다른 구성원 주소를 2–16개 입력하세요.","msig.badMember":"유효한 ndo… 주소가 아닙니다: {a}","msig.badThreshold":"필요 서명 수는 1과 구성원 수 사이여야 합니다.","msig.notProposal":"멀티시그 제안이 아닙니다.","msig.txidMismatch":"제안 id가 내용과 일치하지 않습니다 — 서명하지 마세요.","msig.senderMismatch":"제안의 발신 주소가 구성원 목록과 일치하지 않습니다 — 서명하지 마세요.","msig.derived":"{m}-of-{n} 계정 준비 완료 — 일반 주소처럼 입금하세요.","msig.aliasMissing":"그 별칭은 등록되어 있지 않습니다.","msig.insufficient":"공유 계정 잔액은 {b} NADO — 이 금액 + 수수료에 부족합니다.","msig.proposed":"아래에 제안이 생성되었습니다 — 복사해 공동 서명자에게 전달하세요.","msig.stFrom":"보내는 곳 {a}","msig.stTo":"받는 곳 {a}","msig.stSigs":"서명 {have}/{need}","msig.stExpiry":"블록 {b}까지 유효","msig.stReady":"제출 준비 완료 ✓","msig.stWaiting":"서명했습니다 — 다음 공동 서명자에게 전달하세요.","msig.stYourTurn":"당신의 서명이 필요합니다.","msig.stNotMember":"이 지갑은 계정의 구성원이 아닙니다.","msig.pasteFirst":"먼저 제안을 붙여넣으세요.","msig.signedOk":"서명 추가됨 ✓ — 제안을 복사해 전달하세요(준비되면 제출).","msig.alreadySigned":"추가할 것 없음 — 이미 서명했거나 이 지갑은 구성원이 아닙니다.","msig.dlgTitle":"멀티시그 이체 제출","msig.dlgSigs":"서명","msig.submitted":"제출됨 ✓ — 이체는 몇 블록 안에 온체인에 정산됩니다.","msig.copied":"제안 복사됨 — 공동 서명자에게 보내세요."},
    ar:{"tab.multisig":"توقيع متعدد","msig.title":"توقيع متعدد","msig.pill":"حسابات مشتركة M من N","msig.intro":"حساب مشترك يتطلب M من أصل N توقيعًا من الأعضاء للإنفاق — للأزواج والفرق والضمان أو أمان الجهازين. يُشتق العنوان من قائمة الأعضاء + العتبة؛ موّله كأي عنوان. يُنشئ أحد الأعضاء اقتراحًا، ويضيف كل موقِّع مشارك توقيعه (مرّر نص الاقتراح عبر أي قناة — دردشة أو بريد أو QR)، ويرسله أي شخص متى اكتملت التوقيعات.","msig.members":"عناوين الأعضاء (واحد في كل سطر)","msig.threshold":"التوقيعات المطلوبة للإنفاق (M)","btn.msigDerive":"اشتقاق العنوان المشترك","msig.address":"العنوان المشترك","msig.balance":"الرصيد:","msig.proposeTitle":"اقتراح إنفاق من الحساب المشترك","btn.msigPropose":"إنشاء اقتراح + توقيع","msig.cosignTitle":"الاقتراح — توقيع مشترك وإرسال","msig.cosignIntro":"الصق هنا اقتراحًا استلمته (أو أنشئ واحدًا أعلاه). أضف توقيعك ومرّره — أو أرسله متى اكتملت التوقيعات. تنتهي صلاحية الاقتراحات إذا لم تُرسل خلال ~50 دقيقة من إنشائها.","btn.msigSign":"إضافة توقيعي","btn.msigSubmit":"إرسال","msig.badJson":"هذا ليس اقتراحًا صالحًا ({m}).","msig.badCount":"أدخل من 2 إلى 16 عنوان عضو مختلفًا.","msig.badMember":"ليس عنوان ndo… صالحًا: {a}","msig.badThreshold":"يجب أن يكون عدد التوقيعات المطلوبة بين 1 وعدد الأعضاء.","msig.notProposal":"هذا ليس اقتراح توقيع متعدد.","msig.txidMismatch":"معرّف الاقتراح لا يطابق محتواه — لا توقّعه.","msig.senderMismatch":"مرسل الاقتراح لا يطابق قائمة الأعضاء — لا توقّعه.","msig.derived":"حساب {m} من {n} جاهز — موّله كأي عنوان.","msig.aliasMissing":"هذا الاسم المستعار غير مسجّل.","msig.insufficient":"رصيد الحساب المشترك {b} NADO — لا يكفي لهذا المبلغ + الرسوم.","msig.proposed":"أُنشئ الاقتراح أدناه — انسخه ومرّره إلى الموقّعين المشاركين.","msig.stFrom":"من {a}","msig.stTo":"إلى {a}","msig.stSigs":"التوقيعات {have}/{need}","msig.stExpiry":"صالح حتى الكتلة {b}","msig.stReady":"جاهز للإرسال ✓","msig.stWaiting":"لقد وقّعت — مرّره إلى الموقّع المشارك التالي.","msig.stYourTurn":"توقيعك مطلوب.","msig.stNotMember":"هذه المحفظة ليست عضوًا في الحساب.","msig.pasteFirst":"الصق اقتراحًا أولًا.","msig.signedOk":"أُضيف التوقيع ✓ — انسخ الاقتراح ومرّره (أو أرسله إن كان جاهزًا).","msig.alreadySigned":"لا شيء لإضافته — وقّعت من قبل، أو هذه المحفظة ليست عضوًا.","msig.dlgTitle":"إرسال تحويل متعدد التوقيع","msig.dlgSigs":"التوقيعات","msig.submitted":"أُرسل ✓ — يُسوّى التحويل على السلسلة خلال بضع كتل.","msig.copied":"نُسخ الاقتراح — أرسله إلى موقّع مشارك."},
    hi:{"tab.multisig":"मल्टीसिग","msig.title":"मल्टीसिग","msig.pill":"साझा M-of-N खाते","msig.intro":"एक साझा खाता जिससे खर्च करने के लिए N सदस्यों में से M के हस्ताक्षर चाहिए — जोड़ों, टीमों, एस्क्रो या दो-डिवाइस सुरक्षा के लिए। पता सदस्य सूची + सीमा से निकलता है; इसे किसी भी पते की तरह फंड करें। एक सदस्य प्रस्ताव बनाता है, सह-हस्ताक्षरकर्ता बारी-बारी से हस्ताक्षर जोड़ते हैं (प्रस्ताव का टेक्स्ट किसी भी माध्यम से भेजें — चैट, ईमेल, QR), और पर्याप्त हस्ताक्षर होते ही कोई भी उसे सबमिट कर सकता है।","msig.members":"सदस्यों के पते (प्रति पंक्ति एक)","msig.threshold":"खर्च के लिए ज़रूरी हस्ताक्षर (M)","btn.msigDerive":"साझा पता निकालें","msig.address":"साझा पता","msig.balance":"शेष राशि:","msig.proposeTitle":"साझा खाते से खर्च का प्रस्ताव","btn.msigPropose":"प्रस्ताव बनाएँ + हस्ताक्षर करें","msig.cosignTitle":"प्रस्ताव — सह-हस्ताक्षर और सबमिट","msig.cosignIntro":"मिला हुआ प्रस्ताव यहाँ चिपकाएँ (या ऊपर बनाएँ)। अपना हस्ताक्षर जोड़कर आगे भेजें — या पर्याप्त हस्ताक्षर होने पर सबमिट करें। बनने के ~50 मिनट में सबमिट न होने पर प्रस्ताव समाप्त हो जाता है।","btn.msigSign":"मेरा हस्ताक्षर जोड़ें","btn.msigSubmit":"सबमिट करें","msig.badJson":"यह मान्य प्रस्ताव नहीं है ({m})।","msig.badCount":"2–16 अलग-अलग सदस्य पते दर्ज करें।","msig.badMember":"मान्य ndo… पता नहीं: {a}","msig.badThreshold":"ज़रूरी हस्ताक्षर 1 और सदस्यों की संख्या के बीच होने चाहिए।","msig.notProposal":"यह मल्टीसिग प्रस्ताव नहीं है।","msig.txidMismatch":"प्रस्ताव id उसकी सामग्री से मेल नहीं खाता — हस्ताक्षर न करें।","msig.senderMismatch":"प्रस्ताव का प्रेषक सदस्य सूची से मेल नहीं खाता — हस्ताक्षर न करें।","msig.derived":"{m}-of-{n} खाता तैयार — इसे किसी भी पते की तरह फंड करें।","msig.aliasMissing":"वह उपनाम पंजीकृत नहीं है।","msig.insufficient":"साझा खाते में {b} NADO है — इस राशि + शुल्क के लिए पर्याप्त नहीं।","msig.proposed":"नीचे प्रस्ताव बन गया — कॉपी करके अपने सह-हस्ताक्षरकर्ताओं को भेजें।","msig.stFrom":"से {a}","msig.stTo":"को {a}","msig.stSigs":"हस्ताक्षर {have}/{need}","msig.stExpiry":"ब्लॉक {b} तक मान्य","msig.stReady":"सबमिट के लिए तैयार ✓","msig.stWaiting":"आपने हस्ताक्षर कर दिया — अगले सह-हस्ताक्षरकर्ता को भेजें।","msig.stYourTurn":"आपके हस्ताक्षर की ज़रूरत है।","msig.stNotMember":"यह वॉलेट खाते का सदस्य नहीं है।","msig.pasteFirst":"पहले कोई प्रस्ताव चिपकाएँ।","msig.signedOk":"हस्ताक्षर जुड़ गया ✓ — प्रस्ताव कॉपी करके आगे भेजें (तैयार हो तो सबमिट करें)।","msig.alreadySigned":"जोड़ने को कुछ नहीं — आप पहले ही हस्ताक्षर कर चुके हैं, या यह वॉलेट सदस्य नहीं है।","msig.dlgTitle":"मल्टीसिग ट्रांसफ़र सबमिट करें","msig.dlgSigs":"हस्ताक्षर","msig.submitted":"सबमिट हो गया ✓ — ट्रांसफ़र कुछ ब्लॉकों में ऑन-चेन तय हो जाएगा।","msig.copied":"प्रस्ताव कॉपी हुआ — किसी सह-हस्ताक्षरकर्ता को भेजें।"},
    tr:{"tab.multisig":"Multisig","msig.title":"Multisig","msig.pill":"paylaşılan M/N hesaplar","msig.intro":"Harcamak için N üyeden M imza gerektiren paylaşılan bir hesap — çiftler, ekipler, emanet veya iki cihazlı güvenlik için. Adres, üye listesi + eşikten türetilir; herhangi bir adres gibi fonlayın. Bir üye teklif oluşturur, ortak imzacılar sırayla imza ekler (teklif metnini herhangi bir kanalla iletin — sohbet, e-posta, QR) ve yeterli imza toplandığında herkes gönderebilir.","msig.members":"Üye adresleri (her satıra bir tane)","msig.threshold":"Harcama için gereken imza sayısı (M)","btn.msigDerive":"Paylaşılan adresi türet","msig.address":"Paylaşılan adres","msig.balance":"Bakiye:","msig.proposeTitle":"Paylaşılan hesaptan harcama öner","btn.msigPropose":"Teklif oluştur + imzala","msig.cosignTitle":"Teklif — ortak imzala ve gönder","msig.cosignIntro":"Aldığınız teklifi buraya yapıştırın (veya yukarıda oluşturun). İmzanızı ekleyip iletin — ya da yeterli imza varsa gönderin. Teklifler, oluşturulduktan ~50 dakika içinde gönderilmezse geçersiz olur.","btn.msigSign":"İmzamı ekle","btn.msigSubmit":"Gönder","msig.badJson":"Bu geçerli bir teklif değil ({m}).","msig.badCount":"2–16 farklı üye adresi girin.","msig.badMember":"Geçerli bir ndo… adresi değil: {a}","msig.badThreshold":"Gerekli imza sayısı 1 ile üye sayısı arasında olmalı.","msig.notProposal":"Bu bir multisig teklifi değil.","msig.txidMismatch":"Teklif id'si içeriğiyle uyuşmuyor — imzalamayın.","msig.senderMismatch":"Teklifin göndereni üye listesiyle uyuşmuyor — imzalamayın.","msig.derived":"{m}/{n} hesap hazır — herhangi bir adres gibi fonlayın.","msig.aliasMissing":"Bu takma ad kayıtlı değil.","msig.insufficient":"Paylaşılan hesapta {b} NADO var — bu tutar + ücret için yetersiz.","msig.proposed":"Teklif aşağıda oluşturuldu — kopyalayıp ortak imzacılarınıza iletin.","msig.stFrom":"Gönderen {a}","msig.stTo":"alıcı {a}","msig.stSigs":"imzalar {have}/{need}","msig.stExpiry":"{b}. bloğa kadar geçerli","msig.stReady":"Göndermeye hazır ✓","msig.stWaiting":"İmzaladınız — sıradaki ortak imzacıya iletin.","msig.stYourTurn":"İmzanız gerekiyor.","msig.stNotMember":"Bu cüzdan hesabın üyesi değil.","msig.pasteFirst":"Önce bir teklif yapıştırın.","msig.signedOk":"İmza eklendi ✓ — teklifi kopyalayıp iletin (hazırsa gönderin).","msig.alreadySigned":"Eklenecek bir şey yok — zaten imzaladınız veya bu cüzdan üye değil.","msig.dlgTitle":"Multisig transferini gönder","msig.dlgSigs":"İmzalar","msig.submitted":"Gönderildi ✓ — transfer birkaç blokta zincirde kesinleşir.","msig.copied":"Teklif kopyalandı — bir ortak imzacıya gönderin."},
    id:{"tab.multisig":"Multisig","msig.title":"Multisig","msig.pill":"akun bersama M-dari-N","msig.intro":"Akun bersama yang butuh M dari N tanda tangan anggota untuk membelanjakan — untuk pasangan, tim, escrow, atau keamanan dua perangkat. Alamat diturunkan dari daftar anggota + ambang; isi saldonya seperti alamat biasa. Satu anggota membuat proposal, tiap penandatangan ikut menambahkan tanda tangan (kirim teks proposal lewat kanal apa pun — chat, email, QR), dan siapa pun bisa mengirimkannya begitu tanda tangan cukup.","msig.members":"Alamat anggota (satu per baris)","msig.threshold":"Tanda tangan yang dibutuhkan (M)","btn.msigDerive":"Turunkan alamat bersama","msig.address":"Alamat bersama","msig.balance":"Saldo:","msig.proposeTitle":"Usulkan pengeluaran dari akun bersama","btn.msigPropose":"Buat proposal + tanda tangani","msig.cosignTitle":"Proposal — tanda tangani bersama & kirim","msig.cosignIntro":"Tempel proposal yang Anda terima di sini (atau buat di atas). Tambahkan tanda tangan Anda lalu teruskan — atau kirim begitu tanda tangan cukup. Proposal kedaluwarsa jika tidak dikirim dalam ~50 menit sejak dibuat.","btn.msigSign":"Tambahkan tanda tangan saya","btn.msigSubmit":"Kirim","msig.badJson":"Ini bukan proposal yang valid ({m}).","msig.badCount":"Masukkan 2–16 alamat anggota yang berbeda.","msig.badMember":"Bukan alamat ndo… yang valid: {a}","msig.badThreshold":"Jumlah tanda tangan harus antara 1 dan jumlah anggota.","msig.notProposal":"Ini bukan proposal multisig.","msig.txidMismatch":"Id proposal tidak cocok dengan isinya — jangan tanda tangani.","msig.senderMismatch":"Pengirim proposal tidak cocok dengan daftar anggotanya — jangan tanda tangani.","msig.derived":"Akun {m}-dari-{n} siap — isi saldonya seperti alamat biasa.","msig.aliasMissing":"Alias itu belum terdaftar.","msig.insufficient":"Akun bersama berisi {b} NADO — tidak cukup untuk jumlah + biaya ini.","msig.proposed":"Proposal dibuat di bawah — salin dan teruskan ke para penandatangan.","msig.stFrom":"Dari {a}","msig.stTo":"ke {a}","msig.stSigs":"tanda tangan {have}/{need}","msig.stExpiry":"berlaku sampai blok {b}","msig.stReady":"Siap dikirim ✓","msig.stWaiting":"Anda sudah tanda tangan — teruskan ke penandatangan berikutnya.","msig.stYourTurn":"Tanda tangan Anda dibutuhkan.","msig.stNotMember":"Dompet ini bukan anggota akun.","msig.pasteFirst":"Tempel proposal dulu.","msig.signedOk":"Tanda tangan ditambahkan ✓ — salin proposal dan teruskan (atau kirim jika siap).","msig.alreadySigned":"Tidak ada yang ditambahkan — Anda sudah tanda tangan, atau dompet ini bukan anggota.","msig.dlgTitle":"Kirim transfer multisig","msig.dlgSigs":"Tanda tangan","msig.submitted":"Terkirim ✓ — transfer terselesaikan on-chain dalam beberapa blok.","msig.copied":"Proposal disalin — kirimkan ke seorang penandatangan."},
    vi:{"tab.multisig":"Đa chữ ký","msig.title":"Đa chữ ký","msig.pill":"tài khoản chung M-trong-N","msig.intro":"Tài khoản chung cần M trong N chữ ký thành viên mới chi tiêu được — cho cặp đôi, nhóm, ký quỹ hoặc bảo mật hai thiết bị. Địa chỉ được suy ra từ danh sách thành viên + ngưỡng; nạp tiền như mọi địa chỉ khác. Một thành viên tạo đề xuất, các đồng ký lần lượt thêm chữ ký (chuyển văn bản đề xuất qua kênh bất kỳ — chat, email, QR), và ai cũng có thể gửi khi đủ chữ ký.","msig.members":"Địa chỉ thành viên (mỗi dòng một)","msig.threshold":"Số chữ ký cần để chi tiêu (M)","btn.msigDerive":"Suy ra địa chỉ chung","msig.address":"Địa chỉ chung","msig.balance":"Số dư:","msig.proposeTitle":"Đề xuất chi tiêu từ tài khoản chung","btn.msigPropose":"Tạo đề xuất + ký","msig.cosignTitle":"Đề xuất — đồng ký & gửi","msig.cosignIntro":"Dán đề xuất bạn nhận được vào đây (hoặc tạo ở trên). Thêm chữ ký của bạn rồi chuyển tiếp — hoặc gửi khi đã đủ chữ ký. Đề xuất hết hạn nếu không được gửi trong ~50 phút sau khi tạo.","btn.msigSign":"Thêm chữ ký của tôi","btn.msigSubmit":"Gửi","msig.badJson":"Đây không phải đề xuất hợp lệ ({m}).","msig.badCount":"Nhập 2–16 địa chỉ thành viên khác nhau.","msig.badMember":"Không phải địa chỉ ndo… hợp lệ: {a}","msig.badThreshold":"Số chữ ký yêu cầu phải từ 1 đến số thành viên.","msig.notProposal":"Đây không phải đề xuất đa chữ ký.","msig.txidMismatch":"Id đề xuất không khớp nội dung — đừng ký.","msig.senderMismatch":"Người gửi của đề xuất không khớp danh sách thành viên — đừng ký.","msig.derived":"Tài khoản {m}-trong-{n} đã sẵn sàng — nạp tiền như mọi địa chỉ khác.","msig.aliasMissing":"Bí danh đó chưa được đăng ký.","msig.insufficient":"Tài khoản chung có {b} NADO — không đủ cho số tiền + phí này.","msig.proposed":"Đề xuất đã tạo bên dưới — sao chép và chuyển cho các đồng ký.","msig.stFrom":"Từ {a}","msig.stTo":"đến {a}","msig.stSigs":"chữ ký {have}/{need}","msig.stExpiry":"hiệu lực đến khối {b}","msig.stReady":"Sẵn sàng gửi ✓","msig.stWaiting":"Bạn đã ký — chuyển cho đồng ký tiếp theo.","msig.stYourTurn":"Cần chữ ký của bạn.","msig.stNotMember":"Ví này không phải thành viên của tài khoản.","msig.pasteFirst":"Hãy dán một đề xuất trước.","msig.signedOk":"Đã thêm chữ ký ✓ — sao chép đề xuất và chuyển tiếp (hoặc gửi nếu đã đủ).","msig.alreadySigned":"Không có gì để thêm — bạn đã ký, hoặc ví này không phải thành viên.","msig.dlgTitle":"Gửi chuyển khoản đa chữ ký","msig.dlgSigs":"Chữ ký","msig.submitted":"Đã gửi ✓ — giao dịch chốt trên chuỗi sau vài khối.","msig.copied":"Đã sao chép đề xuất — gửi cho một đồng ký."},
  };
